import { axiosInstance } from "@/lib/axios";
import { ProductsResponse, SingleProductResponse, Category, Brand } from "@/types/product";

export const ProductService = {
  getProducts: async (page = 1, limit = 20, sort?: string, categoryId?: string) => {
    let url = `/api/v1/products?page=${page}&limit=${limit}`;
    if (sort) url += `&sort=${sort}`;
    if (categoryId) url += `&category[in]=${categoryId}`;

    const { data } = await axiosInstance.get<ProductsResponse>(url);
    return data;
  },

  getProductById: async (id: string) => {
    const { data } = await axiosInstance.get<SingleProductResponse>(`/api/v1/products/${id}`);
    return data;
  },

  getCategories: async () => {
    const { data } = await axiosInstance.get<{ data: Category[] }>("/api/v1/categories");
    return data.data;
  },

  getBrands: async () => {
    const { data } = await axiosInstance.get<{ data: Brand[] }>("/api/v1/brands");
    return data.data;
  }
};
